class Solution:
    def escapeGhosts(self, ghosts, target):
        mine = abs(target[0]) + abs(target[1])
        for g in ghosts:
            d = abs(g[0] - target[0]) + abs(g[1] - target[1])
            if d <= mine:
                return False
        return True

