var escapeGhosts = function(ghosts, target) {
    const me = Math.abs(target[0]) + Math.abs(target[1]);
    for (const [x, y] of ghosts) {
        const d = Math.abs(x - target[0]) + Math.abs(y - target[1]);
        if (d <= me) return false;
    }
    return true;
};
